package com.oneil.wellness.walkplanner.calendar.provider.google;
import static org.junit.jupiter.api.Assertions.*;import com.fasterxml.jackson.databind.ObjectMapper;import java.time.Duration;import org.junit.jupiter.api.Test;
class GoogleCalendarEventMapperTest {private final ObjectMapper json=new ObjectMapper();private final GoogleCalendarEventMapper mapper=new GoogleCalendarEventMapper();
 @Test void mapsTimedRecurringTransparentInstance()throws Exception{var event=mapper.map(json.readTree("{\"id\":\"instance\",\"recurringEventId\":\"series\",\"summary\":\"Focus\",\"transparency\":\"transparent\",\"start\":{\"dateTime\":\"2026-07-20T09:00:00-04:00\",\"timeZone\":\"America/New_York\"},\"end\":{\"dateTime\":\"2026-07-20T09:30:00-04:00\"},\"originalStartTime\":{\"dateTime\":\"2026-07-20T09:00:00-04:00\"}}"),"gcal_one","UTC").orElseThrow();assertFalse(event.busy());assertEquals("series",event.providerEventId());assertEquals("America/New_York",event.timezone());assertEquals(Duration.ofMinutes(30),Duration.between(event.startTime(),event.endTime()));}
 @Test void mapsAllDayAndIgnoresCancelled()throws Exception{var allDay=mapper.map(json.readTree("{\"id\":\"day\",\"start\":{\"date\":\"2026-07-20\"},\"end\":{\"date\":\"2026-07-21\"}}"),"gcal_one","America/New_York").orElseThrow();assertTrue(allDay.allDay());assertEquals("America/New_York",allDay.timezone());assertTrue(mapper.map(json.readTree("{\"id\":\"gone\",\"status\":\"cancelled\"}"),"gcal_one","UTC").isEmpty());}
}
